#include <bits/stdc++.h>
using namespace std;
int n,m,dist[1003];
bool b[1003];
vector<int> g[1003],val[1003];
int Dijkstra(int s){
    memset(dist,127,sizeof(dist));
    memset(b,false,sizeof(b));
    int sum=0;
    dist[s]=0;
	while(1){
		int x=0;
		for(int i=1;i<=n;i++)
			if(!b[i] && dist[i]<(1<<30) && dist[i]<dist[x])
				x=i;
		if(!x || (s>1 && x==1))
			break;
		b[x]=true,sum+=dist[x];
		int len=g[x].size();
		for(int i=0;i<len;i++)
			dist[g[x][i]]=min(dist[g[x][i]],dist[x]+val[x][i]);
	}
	if(s>1)
		return dist[1];
	else
		return sum;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int u,v,w;
        cin>>u>>v>>w;
        g[u].push_back(v);
        val[u].push_back(w);
    }
    int ans=0;
    for(int i=1;i<=n;i++)
        ans+=Dijkstra(i);
    cout<<ans;
    return 0;
}
